ORDER BY dict_type, sort, dict_code
    LIMIT #{limit} OFFSET #{offset}

SELECT * FROM sys_dict WHERE 1=1
AND dict_type = #{dictType}
AND dict_code LIKE CONCAT('%', #{dictCode}, '%')
AND dict_name LIKE CONCAT('%', #{dictName}, '%')
AND status = #{status}
ORDER BY dict_type, sort, dict_code

SELECT COUNT(1) FROM sys_dict
WHERE 1=1

    AND dict_type = #{dictType}


    AND dict_code LIKE CONCAT('%', #{dictCode}, '%')


    AND dict_name LIKE CONCAT('%', #{dictName}, '%')


    AND status = #{status}

